#define MCU_FONT_INDEX_REC_SIZE 13u

static uint32_t mcu_font_rd24(const uint8_t *p) {
    return (uint32_t)p[0] | ((uint32_t)p[1] << 8) | ((uint32_t)p[2] << 16);
}

static uint16_t mcu_font_rd16(const uint8_t *p) {
    return (uint16_t)((uint16_t)p[0] | ((uint16_t)p[1] << 8));
}

/* 二分查找字形索引记录，未找到返回 NULL */
static const uint8_t *mcu_font_find(uint32_t codepoint) {
    uint32_t lo = 0u, hi = MCU_FONT_GLYPH_COUNT;
    while (lo < hi) {
        uint32_t mid = (lo + hi) >> 1;
        const uint8_t *rec = mcu_font_index + mid * MCU_FONT_INDEX_REC_SIZE;
        uint32_t c = mcu_font_rd24(rec);
        if (codepoint < c) { hi = mid; }
        else if (codepoint > c) { lo = mid + 1u; }
        else { return rec; }
    }
    return NULL;
}

/* RLE 解码：src/len 为某字形的 mask 段，dst 容量 >= total（= w*h），纯整数运算 */
static void mcu_font_decode(const uint8_t *src, uint16_t len, uint8_t *dst, uint16_t total) {
    uint16_t i = 0u, pos = 0u;
    while ((i < len) && (pos < total)) {
        uint8_t token = src[i++];
        if (token < 0x80u) {
            uint16_t run = (uint16_t)token + 1u;
            while ((run-- > 0u) && (pos < total)) { dst[pos++] = 0u; }
        } else {
            uint16_t count = (uint16_t)(token & 0x7Fu) + 1u;
            uint16_t k;
            for (k = 0u; (k < count) && (pos < total); k++) {
                uint8_t b = src[i + (k >> 1)];
                dst[pos++] = ((k & 1u) != 0u) ? (uint8_t)(b & 0x0Fu) : (uint8_t)(b >> 4);
            }
            i = (uint16_t)(i + ((count + 1u) >> 1));
        }
    }
    while (pos < total) { dst[pos++] = 0u; }
}

/* 对外接口：按 Unicode 码点取字模
 *   alpha     : 调用者提供的缓冲区（>= w*h 字节），传 NULL 则只取元数据
 *   w/h       : 字模位图宽/高
 *   x_offset  : 位图左缘相对笔位的偏移（可为负）
 *   y_offset  : 基线到位图顶部的距离（向上为正；可为负，如 '_' 等整体位于基线下方的字符）
 *   x_advance : 笔位步进宽度
 *   返回值    : 1 = 找到，0 = 未找到
 */
static uint8_t mcu_font_get_glyph(uint32_t codepoint, uint8_t *alpha,
                                  uint8_t *w, uint8_t *h,
                                  int8_t *x_offset, int8_t *y_offset, uint8_t *x_advance) {
    const uint8_t *rec = mcu_font_find(codepoint);
    uint8_t gw, gh;
    if (rec == NULL) { return 0u; }
    gw = rec[3]; gh = rec[4];
    if (w != NULL) { *w = gw; }
    if (h != NULL) { *h = gh; }
    if (x_offset != NULL) { *x_offset = (int8_t)rec[5]; }
    if (y_offset != NULL) { *y_offset = (int8_t)rec[6]; }
    if (x_advance != NULL) { *x_advance = rec[7]; }
    if (alpha != NULL) {
        mcu_font_decode(mcu_font_mask + mcu_font_rd24(rec + 8u),
                        mcu_font_rd16(rec + 11u), alpha,
                        (uint16_t)((uint16_t)gw * (uint16_t)gh));
    }
    return 1u;
}

